var e=[{id:`L2_1`,type:`dialog`,speaker:`TOMY_MASON_NULL_NULL`,text:{KOREA:`후후, 저번에는 심사위원이었지만 이번에는 경쟁자로 다시 만나는군.`,JPN:`ふふ、この前は審査員だったが、今度は敵としてまた会うとはな。`,ENG:`Hah hah! I was your judge in the last challenge, but now we meet as competitors.`,TWN:`呵呵，上次見面我是評審，這次卻是以競爭對手的身分相遇。`},stage:{bg:`CLOSE`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`JERRY_MASON_NULL_NULL`,text:{KOREA:`그런데 저 요호호 웃는 여자애, 어디서 본 것 같지 않아?`,JPN:`てかあのヨホホって笑う女の子、どっかで見たことないか？`,ENG:`Hey, does that "yo ho ho" girl look familiar?`,TWN:`不過那個哇哈哈笑的女生，不覺得好像在哪看過嗎？`},stage:{bg:`CLOSE`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`MICKEY_MASON_NULL_NULL`,text:{KOREA:`훗. 하지만 승부의 세계는 냉정한 법. 아는 사이라고 봐 줄 수 없지.`,JPN:`ふっ。だが勝負の世界は冷酷だ。知り合いだからって手加減はできない。`,ENG:`Pfft. I play to win, not for fun. Don't go easy on them just because you know them.`,TWN:`呵，不過在賽場上是不留情面的，就算是認識的人也不能放水。`},stage:{bg:`CLOSE`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}}];export{e as default};